protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex throws at startup in EF Core 9 Cosmos — manage indexing
    // via the container's indexing policy (Azure Portal / Bicep / Terraform).

    modelBuilder.Entity<Product>(b =>
    {
        b.ToContainer("Products");

        // EF Core 9 renamed the default discriminator property from
        // "Discriminator" to "$type". Existing 500K documents use the old
        // name, and direct SQL queries reference c.Discriminator.
        b.HasDiscriminator<string>("Discriminator");

        // EF Core 9 stopped embedding the discriminator in the JSON id.
        // Existing documents have ids like "Product|123". Without this
        // flag, FindAsync would look for "123" and miss every stored doc.
        b.HasRootDiscriminatorInJsonId(true);
    });
}

