using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O.
    // All queries and saves must use async equivalents.
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe: c.Discriminator is preserved by the
        // HasDiscriminator("Discriminator") configuration in ProductContext.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // ToList() throws in EF Core 9 Cosmos — use ToListAsync().
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

